import { useState, useCallback, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "@/contexts/AuthContext";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import { motion } from "framer-motion";
import axios from "axios";
import {
  Upload, ScanEye, Loader2, Image, Film, X, ArrowRight, Clock, Zap, AlertTriangle, Trash2,
  BarChart3, Shield, Sparkles, ChevronRight, TrendingUp
} from "lucide-react";

const API = `${process.env.REACT_APP_BACKEND_URL}/api`;

const PLAN_LABELS = { free: "Free", vip: "VIP", premium: "Premium" };
const PLAN_COLORS = {
  free: "bg-secondary text-secondary-foreground",
  vip: "bg-emerald-500/10 text-emerald-400 border-emerald-500/20",
  premium: "bg-violet-500/10 text-violet-400 border-violet-500/20"
};

const fadeUp = {
  hidden: { opacity: 0, y: 30 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.5, ease: "easeOut" } }
};
const stagger = { visible: { transition: { staggerChildren: 0.1 } } };

export default function DashboardPage() {
  const { token, user } = useAuth();
  const navigate = useNavigate();
  const [dragging, setDragging] = useState(false);
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [recentAnalyses, setRecentAnalyses] = useState([]);
  const [loadingRecent, setLoadingRecent] = useState(true);
  const [usage, setUsage] = useState(null);
  const uploadRef = useRef(null);

  const fetchUsage = useCallback(async () => {
    try {
      const res = await axios.get(`${API}/auth/usage`, {
        headers: { authorization: `Bearer ${token}` }
      });
      setUsage(res.data);
    } catch (err) {
      console.error("Failed to fetch usage");
    }
  }, [token]);

  const fetchRecent = useCallback(async () => {
    try {
      const res = await axios.get(`${API}/analyses`, {
        headers: { authorization: `Bearer ${token}` }
      });
      setRecentAnalyses(res.data.slice(0, 6));
    } catch (err) {
      console.error("Failed to fetch analyses");
    }
    setLoadingRecent(false);
  }, [token]);

  useEffect(() => {
    fetchRecent();
    fetchUsage();
  }, [fetchRecent, fetchUsage]);

  const handleFile = (f) => {
    if (!f) return;
    const validTypes = ['image/jpeg', 'image/png', 'image/webp', 'video/mp4', 'video/quicktime', 'video/webm'];
    if (!validTypes.includes(f.type)) {
      toast.error("Unsupported file type. Use JPEG, PNG, WebP, or MP4.");
      return;
    }
    if (f.size > 10 * 1024 * 1024) {
      toast.error("File too large. Max 10MB.");
      return;
    }
    setFile(f);
    const url = URL.createObjectURL(f);
    setPreview(url);
    // Scroll to upload zone
    setTimeout(() => uploadRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' }), 100);
  };

  const onDrop = useCallback((e) => {
    e.preventDefault();
    setDragging(false);
    const f = e.dataTransfer.files[0];
    handleFile(f);
  }, []);

  const onDragOver = (e) => { e.preventDefault(); setDragging(true); };
  const onDragLeave = () => setDragging(false);

  const handleAnalyze = async () => {
    if (!file) return;
    setAnalyzing(true);
    try {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("authorization", `Bearer ${token}`);
      const res = await axios.post(`${API}/analyze`, formData, {
        headers: { "Content-Type": "multipart/form-data" },
        timeout: 60000,
      });
      toast.success("Analysis complete!");
      navigate(`/result/${res.data.id}`);
    } catch (err) {
      const msg = err.response?.data?.detail || "Analysis failed. Please try again.";
      if (err.response?.status === 429) {
        toast.error(msg, { duration: 6000 });
        fetchUsage();
      } else {
        toast.error(msg);
      }
    }
    setAnalyzing(false);
  };

  const handleDelete = async (e, id) => {
    e.stopPropagation();
    try {
      await axios.delete(`${API}/analyses/${id}`, {
        headers: { authorization: `Bearer ${token}` }
      });
      toast.success("Analysis deleted");
      fetchRecent();
      fetchUsage();
    } catch {
      toast.error("Failed to delete");
    }
  };

  const clearFile = () => { setFile(null); setPreview(null); };
  const isVideo = file?.type?.startsWith("video/");
  const limitReached = usage && usage.remaining === 0;
  const firstName = user?.name?.split(" ")[0] || "there";

  return (
    <div className="min-h-screen" data-testid="dashboard-page">

      {/* ─── HERO SECTION ─── */}
      <section className="relative overflow-hidden pt-24 pb-20 px-4">
        {/* Ambient background */}
        <div className="absolute inset-0 bg-background pointer-events-none">
          <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top_right,hsl(var(--brand-real)/0.10),transparent_55%)]" />
          <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_bottom_left,hsl(var(--brand-fake)/0.07),transparent_55%)]" />
          <div className="absolute inset-0 opacity-[0.025]" style={{
            backgroundImage: 'linear-gradient(hsl(var(--foreground)) 1px, transparent 1px), linear-gradient(90deg, hsl(var(--foreground)) 1px, transparent 1px)',
            backgroundSize: '50px 50px'
          }} />
        </div>

        <div className="relative max-w-6xl mx-auto">
          <motion.div
            initial="hidden" animate="visible" variants={stagger}
            className="flex flex-col lg:flex-row items-center gap-16"
          >
            {/* Left: Text */}
            <div className="flex-1 text-left">
              <motion.div variants={fadeUp}>
                <Badge variant="outline" className="mb-6 px-3 py-1.5 rounded-sm font-mono text-xs gap-1.5 border-foreground/20">
                  <Sparkles className="w-3 h-3" />
                  Welcome back, {firstName}
                </Badge>
              </motion.div>

              <motion.h1
                variants={fadeUp}
                className="text-4xl sm:text-5xl lg:text-6xl font-black tracking-tight leading-[1.1] mb-6"
              >
                Detect{" "}
                <span className="text-[hsl(var(--brand-fake))]">AI fakes</span>
                <br />in seconds
              </motion.h1>

              <motion.p variants={fadeUp} className="text-base md:text-lg text-muted-foreground leading-relaxed mb-10 max-w-md">
                Drop any image or video and our AI engine delivers a confidence-scored verdict with detailed analysis across 6 categories.
              </motion.p>

              <motion.div variants={fadeUp} className="flex flex-wrap gap-3">
                <Button
                  size="lg"
                  onClick={() => uploadRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' })}
                  className="rounded-sm gap-2 text-base px-7 h-12 active:scale-95 transition-all"
                  data-testid="hero-analyze-button"
                >
                  <Upload className="w-4 h-4" />
                  Analyze Now
                </Button>
                <Button
                  variant="outline"
                  size="lg"
                  onClick={() => navigate("/history")}
                  className="rounded-sm gap-2 text-base px-7 h-12"
                >
                  <Clock className="w-4 h-4" />
                  View History
                </Button>
              </motion.div>

              {/* Quick stats */}
              {usage && (
                <motion.div variants={fadeUp} className="mt-12 flex gap-8 flex-wrap">
                  <div>
                    <p className="text-2xl font-black font-mono">
                      <span className={limitReached ? 'text-destructive' : 'text-[hsl(var(--brand-real))]'}>
                        {usage.remaining}
                      </span>
                      <span className="text-muted-foreground text-lg">/{usage.daily_limit}</span>
                    </p>
                    <p className="text-xs text-muted-foreground mt-0.5">Analyses left today</p>
                  </div>
                  <div>
                    <p className="text-2xl font-black font-mono">{recentAnalyses.length}</p>
                    <p className="text-xs text-muted-foreground mt-0.5">Recent scans</p>
                  </div>
                  <div>
                    <Badge variant="outline" className={`px-3 py-1 rounded-sm font-mono text-sm ${PLAN_COLORS[usage.plan] || ''}`}>
                      {PLAN_LABELS[usage.plan] || usage.plan} Plan
                    </Badge>
                    <p className="text-xs text-muted-foreground mt-1.5">Current plan</p>
                  </div>
                </motion.div>
              )}
            </div>

            {/* Right: Floating mock card */}
            <motion.div
              initial={{ opacity: 0, x: 60, rotate: 2 }}
              animate={{ opacity: 1, x: 0, rotate: 2 }}
              transition={{ delay: 0.5, duration: 0.8 }}
              className="hidden lg:block flex-shrink-0 w-80"
            >
              <div className="rounded-sm border bg-card p-6 shadow-lg animate-float">
                <div className="flex items-center gap-3 mb-5">
                  <div className="w-10 h-10 rounded-sm bg-[hsl(var(--brand-fake)/0.12)] flex items-center justify-center">
                    <ScanEye className="w-5 h-5 text-[hsl(var(--brand-fake))]" />
                  </div>
                  <div>
                    <p className="text-sm font-semibold">Analysis Complete</p>
                    <p className="text-xs text-muted-foreground">portrait_2024.jpg</p>
                  </div>
                </div>
                <div className="space-y-3">
                  <div className="flex justify-between items-center">
                    <span className="text-xs text-muted-foreground">Verdict</span>
                    <Badge className="bg-[hsl(var(--brand-fake)/0.1)] text-[hsl(var(--brand-fake))] border-[hsl(var(--brand-fake)/0.2)] rounded-sm text-xs">
                      AI-Generated
                    </Badge>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-xs text-muted-foreground">Confidence</span>
                    <span className="font-mono text-sm font-bold">94.7%</span>
                  </div>
                  <div className="h-2 rounded-full bg-secondary overflow-hidden">
                    <motion.div
                      initial={{ width: 0 }}
                      animate={{ width: '94.7%' }}
                      transition={{ delay: 1, duration: 1.2, ease: "easeOut" }}
                      className="h-full rounded-full bg-[hsl(var(--brand-fake))]"
                    />
                  </div>
                  <div className="pt-2 border-t mt-3 space-y-1.5">
                    {["Texture & Patterns", "Lighting & Shadows", "Edge Quality"].map((cat, i) => (
                      <div key={cat} className="flex items-center gap-2">
                        <div className={`w-1.5 h-1.5 rounded-full ${i === 1 ? 'bg-[hsl(var(--brand-real))]' : 'bg-[hsl(var(--brand-fake))]'}`} />
                        <span className="text-xs text-muted-foreground">{cat}</span>
                        <span className="ml-auto text-xs font-mono text-muted-foreground">{i === 1 ? 'Real' : 'AI'}</span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </motion.div>
          </motion.div>
        </div>
      </section>

      {/* ─── LIMIT REACHED BANNER ─── */}
      {limitReached && (
        <div className="px-4">
          <div className="max-w-6xl mx-auto">
            <motion.div
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              className="mb-2 p-4 rounded-sm border border-destructive/30 bg-destructive/10 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4"
            >
              <div className="flex items-start gap-3">
                <AlertTriangle className="w-5 h-5 text-destructive shrink-0 mt-0.5" />
                <div>
                  <p className="font-semibold text-sm">Daily limit reached!</p>
                  <p className="text-xs text-muted-foreground">
                    You've used all {usage.daily_limit} analyses today on the <span className="font-medium capitalize">{usage.plan}</span> plan.
                  </p>
                </div>
              </div>
              <Button
                size="sm"
                onClick={() => navigate("/pricing")}
                className="rounded-sm gap-2 bg-gradient-to-r from-emerald-500 to-teal-500 text-white border-0 shrink-0"
              >
                <Zap className="w-4 h-4" />
                Upgrade Plan
              </Button>
            </motion.div>
          </div>
        </div>
      )}

      {/* ─── UPLOAD ZONE ─── */}
      <section className="px-4 pb-8">
        <div className="max-w-6xl mx-auto">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            ref={uploadRef}
          >
            <div className="flex items-center gap-2 mb-5">
              <div className="w-1 h-5 rounded-full bg-gradient-to-b from-[hsl(var(--brand-real))] to-[hsl(var(--brand-fake))]" />
              <h2 className="text-lg font-bold tracking-tight">Analyze Media</h2>
            </div>

            {!file ? (
              <div
                onDrop={onDrop}
                onDragOver={onDragOver}
                onDragLeave={onDragLeave}
                className={`relative rounded-sm border-2 border-dashed p-14 text-center cursor-pointer transition-all duration-300 group ${
                  dragging
                    ? "border-[hsl(var(--brand-real))] bg-[hsl(var(--brand-real)/0.05)]"
                    : "border-border hover:border-[hsl(var(--brand-real)/0.6)] hover:bg-[hsl(var(--brand-real)/0.02)]"
                }`}
                onClick={() => document.getElementById("file-input").click()}
                data-testid="upload-dropzone"
              >
                {dragging && (
                  <div className="absolute inset-0 overflow-hidden rounded-sm">
                    <div className="absolute inset-x-0 h-0.5 bg-gradient-to-r from-transparent via-[hsl(var(--brand-real))] to-transparent animate-scan-line" />
                  </div>
                )}

                <div className="flex flex-col items-center gap-5">
                  <div className={`w-20 h-20 rounded-sm flex items-center justify-center transition-all duration-300 ${dragging ? 'bg-[hsl(var(--brand-real)/0.15)]' : 'bg-secondary group-hover:bg-[hsl(var(--brand-real)/0.08)]'}`}>
                    <Upload className={`w-9 h-9 transition-colors duration-300 ${dragging ? 'text-[hsl(var(--brand-real))]' : 'text-muted-foreground group-hover:text-[hsl(var(--brand-real))]'}`} />
                  </div>
                  <div>
                    <p className="font-semibold text-lg mb-1">
                      {dragging ? "Drop to analyze" : "Drop file or click to browse"}
                    </p>
                    <p className="text-sm text-muted-foreground">
                      JPEG, PNG, WebP, MP4 — Max 10MB
                    </p>
                  </div>
                  <div className="flex gap-3 flex-wrap justify-center">
                    {["Image", "Video", "Up to 10MB", "Instant results"].map(tag => (
                      <span key={tag} className="text-xs px-2.5 py-1 rounded-sm bg-secondary text-muted-foreground font-mono">
                        {tag}
                      </span>
                    ))}
                  </div>
                </div>
                <input
                  id="file-input"
                  type="file"
                  accept="image/jpeg,image/png,image/webp,video/mp4,video/quicktime,video/webm"
                  onChange={(e) => handleFile(e.target.files[0])}
                  className="hidden"
                  data-testid="file-input"
                />
              </div>
            ) : (
              <Card className="rounded-sm overflow-hidden border">
                <CardContent className="p-0">
                  <div className="flex flex-col md:flex-row">
                    {/* Preview */}
                    <div className="relative md:w-1/2 bg-secondary/20 flex items-center justify-center min-h-[300px]">
                      {isVideo ? (
                        <video src={preview} className="max-h-[400px] w-full object-contain" controls data-testid="video-preview" />
                      ) : (
                        <img src={preview} alt="Preview" className="max-h-[400px] w-full object-contain" data-testid="image-preview" />
                      )}
                      <Button
                        variant="ghost"
                        size="icon"
                        className="absolute top-3 right-3 rounded-sm bg-background/80 backdrop-blur-sm"
                        onClick={clearFile}
                        data-testid="clear-file-button"
                      >
                        <X className="w-4 h-4" />
                      </Button>
                    </div>

                    {/* Info & Analyze */}
                    <div className="md:w-1/2 p-8 flex flex-col justify-center">
                      <div className="flex items-center gap-3 mb-6">
                        {isVideo ? (
                          <Film className="w-5 h-5 text-muted-foreground" />
                        ) : (
                          <Image className="w-5 h-5 text-muted-foreground" />
                        )}
                        <div>
                          <p className="font-medium text-sm truncate max-w-[250px]">{file.name}</p>
                          <p className="text-xs text-muted-foreground">
                            {(file.size / 1024 / 1024).toFixed(2)} MB — {file.type}
                          </p>
                        </div>
                      </div>

                      <div className="space-y-2 mb-8 p-4 rounded-sm bg-secondary/40 border">
                        <p className="text-xs font-mono text-muted-foreground uppercase tracking-wider mb-3">Will analyze</p>
                        {["Texture & Patterns", "Lighting & Shadows", "Facial Features", "Background Consistency", "Edge Quality", "Metadata Artifacts"].map(cat => (
                          <div key={cat} className="flex items-center gap-2 text-sm text-muted-foreground">
                            <div className="w-1 h-1 rounded-full bg-[hsl(var(--brand-real))]" />
                            <span>{cat}</span>
                          </div>
                        ))}
                      </div>

                      <Button
                        onClick={handleAnalyze}
                        disabled={analyzing || limitReached}
                        className="rounded-sm gap-2 h-12 active:scale-95 transition-all text-base"
                        data-testid="analyze-button"
                      >
                        {analyzing ? (
                          <>
                            <Loader2 className="w-4 h-4 animate-spin" />
                            Analyzing...
                          </>
                        ) : (
                          <>
                            <ScanEye className="w-4 h-4" />
                            Run Analysis
                          </>
                        )}
                      </Button>

                      {analyzing && (
                        <div className="mt-4 p-3 rounded-sm bg-secondary/50 border">
                          <div className="flex items-center gap-2 text-sm text-muted-foreground">
                            <div className="w-2 h-2 rounded-full bg-[hsl(var(--brand-real))] animate-pulse" />
                            Processing with Gemini Vision...
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                </CardContent>
              </Card>
            )}
          </motion.div>
        </div>
      </section>

      {/* ─── FEATURE HIGHLIGHTS (for first time / empty state) ─── */}
      {!loadingRecent && recentAnalyses.length === 0 && (
        <section className="px-4 py-8">
          <div className="max-w-6xl mx-auto">
            <motion.div
              initial="hidden"
              animate="visible"
              variants={stagger}
              className="grid sm:grid-cols-3 gap-4"
            >
              {[
                { icon: Shield, title: "6-Point Analysis", desc: "Texture, lighting, faces, edges, and more.", color: "text-[hsl(var(--brand-real))]", bg: "bg-[hsl(var(--brand-real)/0.08)]" },
                { icon: Zap, title: "Instant Results", desc: "Get detailed verdict in under 3 seconds.", color: "text-violet-400", bg: "bg-violet-500/10" },
                { icon: BarChart3, title: "Confidence Score", desc: "Precise percentage with full reasoning.", color: "text-[hsl(var(--brand-fake))]", bg: "bg-[hsl(var(--brand-fake)/0.08)]" },
              ].map((item) => (
                <motion.div
                  key={item.title}
                  variants={fadeUp}
                  className="rounded-sm border bg-card p-6 hover:shadow-md transition-all duration-200 hover:-translate-y-1"
                >
                  <div className={`w-10 h-10 rounded-sm ${item.bg} flex items-center justify-center mb-4`}>
                    <item.icon className={`w-5 h-5 ${item.color}`} />
                  </div>
                  <h3 className="font-bold mb-2">{item.title}</h3>
                  <p className="text-sm text-muted-foreground leading-relaxed">{item.desc}</p>
                </motion.div>
              ))}
            </motion.div>
          </div>
        </section>
      )}

      {/* ─── RECENT ANALYSES ─── */}
      <section className="px-4 pb-24 pt-4">
        <div className="max-w-6xl mx-auto">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
          >
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <div className="w-1 h-5 rounded-full bg-gradient-to-b from-violet-400 to-violet-600" />
                <h2 className="text-lg font-bold tracking-tight">Recent Analyses</h2>
              </div>
              {recentAnalyses.length > 0 && (
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => navigate("/history")}
                  className="rounded-sm gap-1 text-muted-foreground hover:text-foreground"
                  data-testid="view-all-history-button"
                >
                  View All <ChevronRight className="w-3.5 h-3.5" />
                </Button>
              )}
            </div>

            {loadingRecent ? (
              <div className="flex items-center justify-center py-16">
                <Loader2 className="w-6 h-6 animate-spin text-muted-foreground" />
              </div>
            ) : recentAnalyses.length === 0 ? (
              <div className="rounded-sm border border-dashed bg-card/50 py-16 text-center">
                <div className="w-14 h-14 rounded-sm bg-secondary flex items-center justify-center mx-auto mb-4">
                  <TrendingUp className="w-6 h-6 text-muted-foreground" />
                </div>
                <p className="font-semibold mb-1">No analyses yet</p>
                <p className="text-sm text-muted-foreground mb-6">Upload your first file above to get started</p>
                <Button
                  size="sm"
                  variant="outline"
                  className="rounded-sm gap-2"
                  onClick={() => uploadRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' })}
                >
                  <Upload className="w-3.5 h-3.5" />
                  Upload File
                </Button>
              </div>
            ) : (
              <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {recentAnalyses.map((a, i) => (
                  <motion.div
                    key={a.id}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.1 * i }}
                  >
                    <Card
                      className="rounded-sm cursor-pointer hover:shadow-lg transition-all duration-200 hover:-translate-y-1 overflow-hidden group"
                      onClick={() => navigate(`/result/${a.id}`)}
                      data-testid={`analysis-card-${a.id}`}
                    >
                      <div className="relative">
                        {/* Delete button */}
                        <Button
                          variant="destructive"
                          size="icon"
                          className="absolute top-2 left-2 w-7 h-7 rounded-sm opacity-0 group-hover:opacity-100 transition-opacity z-10"
                          onClick={(e) => handleDelete(e, a.id)}
                        >
                          <Trash2 className="w-3.5 h-3.5" />
                        </Button>

                        {/* Thumbnail */}
                        {a.file_preview ? (
                          <div className="h-36 bg-secondary/30 overflow-hidden">
                            <img
                              src={a.file_preview}
                              alt={a.original_filename}
                              className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                            />
                          </div>
                        ) : (
                          <div className="h-36 bg-secondary/30 flex items-center justify-center">
                            {a.file_type === 'video'
                              ? <Film className="w-8 h-8 text-muted-foreground/40" />
                              : <Image className="w-8 h-8 text-muted-foreground/40" />
                            }
                          </div>
                        )}

                        {/* Verdict overlay at bottom of thumbnail */}
                        <div className="absolute bottom-0 left-0 right-0 h-10 bg-gradient-to-t from-background/80 to-transparent flex items-end px-3 pb-1.5">
                          <Badge
                            className={`rounded-sm text-xs ${
                              a.verdict === "Likely Real"
                                ? "bg-[hsl(var(--brand-real)/0.15)] text-[hsl(var(--brand-real))] border-[hsl(var(--brand-real)/0.25)]"
                                : "bg-[hsl(var(--brand-fake)/0.15)] text-[hsl(var(--brand-fake))] border-[hsl(var(--brand-fake)/0.25)]"
                            }`}
                            data-testid={`verdict-badge-${a.id}`}
                          >
                            {a.verdict}
                          </Badge>
                        </div>
                      </div>

                      <CardContent className="p-3.5">
                        <div className="flex items-center justify-between">
                          <p className="text-sm font-medium truncate max-w-[150px]">{a.original_filename}</p>
                          <span className="font-mono text-sm font-bold">
                            {a.confidence_score.toFixed(1)}%
                          </span>
                        </div>
                        <div className="mt-2 h-1.5 rounded-full bg-secondary overflow-hidden">
                          <div
                            className={`h-full rounded-full ${a.verdict === "Likely Real" ? "bg-[hsl(var(--brand-real))]" : "bg-[hsl(var(--brand-fake))]"}`}
                            style={{ width: `${a.confidence_score}%` }}
                          />
                        </div>
                        <p className="text-xs text-muted-foreground mt-2">
                          {new Date(a.created_at).toLocaleDateString("en-US", { month: 'short', day: 'numeric', year: 'numeric' })}
                        </p>
                      </CardContent>
                    </Card>
                  </motion.div>
                ))}
              </div>
            )}
          </motion.div>
        </div>
      </section>
    </div>
  );
}
